// Row struct
USTRUCT(BlueprintType)
struct FWeaponData : public FTableRowBase {
    GENERATED_BODY()

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    FText DisplayName;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    float Damage;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    float FireRate;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    TSoftObjectPtr<UStaticMesh> WeaponMesh;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    TSubclassOf<AProjectile> ProjectileClass;
};

// Looking up a row
void AMyWeapon::LoadWeaponData(FName WeaponID) {
    if (FWeaponData* Row = WeaponTable->FindRow<FWeaponData>(WeaponID, TEXT("LoadWeapon"))) {
        Damage = Row->Damage;
        FireRate = Row->FireRate;
    }
}

// Get all rows
TArray<FWeaponData*> AllWeapons;
WeaponTable->GetAllRows<FWeaponData>(TEXT(""), AllWeapons);

// Simple Data Asset for character class definition
UCLASS()
class UCharacterClassData : public UPrimaryDataAsset {
    GENERATED_BODY()
public:
    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    FText ClassName;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    float BaseHealth;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    float BaseMana;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    TArray<TSubclassOf<UGameplayAbility>> StartingAbilities;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    TSubclassOf<ACharacter> CharacterClass;

    virtual FPrimaryAssetId GetPrimaryAssetId() const override {
        return FPrimaryAssetId("CharacterClass", GetFName());
    }
};

// Reference in other classes
UPROPERTY(EditAnywhere)
UCharacterClassData* SelectedClass;

// Damage falloff curve (distance → damage multiplier)
UPROPERTY(EditAnywhere, Category="Damage")
UCurveFloat* DamageFalloffCurve;

float AMyWeapon::CalculateDamage(float Distance) {
    float Multiplier = 1.f;
    if (DamageFalloffCurve) {
        Multiplier = DamageFalloffCurve->GetFloatValue(Distance);
    }
    return BaseDamage * Multiplier;
}

// Inline editable curve (no separate asset needed)
UPROPERTY(EditAnywhere, Category="Scaling")
FRuntimeFloatCurve DifficultyCurve;

float GetDifficultyMultiplier(float GameTime) {
    if (const FRichCurve* Curve = DifficultyCurve.GetRichCurveConst()) {
        return Curve->Eval(GameTime);
    }
    return 1.f;
}
